INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('lamborghini-urus', 'lamborghini', '兰博基尼 Urus', '2022', '高性能SUV', 'b1.svg', '3,200', '4.0L V8', '汽油', '自动挡', '高性能 SUV', '四轮驱动', '曜石黑', '黑色真皮', '5 座', '意大利进口', 5600, 120000, 2, 'available', '["这台 Lamborghini Urus 保持了完整保养记录与出色的整体状态，在高性能 SUV 的张力之外，也保留了足够从容的日常使用感。","车身姿态、内饰质感与机械完成度都处于很整齐的水准，适合被当作兼顾性能表达与通勤场景的一台主力座驾。"]', '["この Lamborghini Urus は整備履歴が明確で、全体のコンディションも非常に整っています。高性能 SUV らしい緊張感を保ちながら、日常域では落ち着いた扱いやすさも感じられる一台です。","ボディの佇まい、内装の質感、機関系のまとまりまで全体の完成度が高く、パフォーマンス性と日常使いを両立したメインカーとして自然に選べる内容です。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 0, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-urus', 'seed:vehicles/seed/001.png', '/api/media/vehicles/seed/001.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-urus', 'seed:vehicles/seed/001.png', '/api/media/vehicles/seed/001.png', '', 0, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-urus', 'seed:vehicles/seed/001.png', '/api/media/vehicles/seed/001.png', '', 0, 2);
