INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('audi-r8-spyder', 'audi', '奥迪 R8 Spyder', '2023', '敞篷跑车', 'b2.svg', '90', '5.2L V10', '汽油', '自动挡', '双门跑车', '四轮驱动', '曜石黑', '棕色真皮', '2 座', '德国进口', 4800, 100000, 2, 'available', '["这台奥迪 R8 保持了低里程与完整保养记录，低伏车身与中置布局让整车始终带着很鲜明的超跑比例。","无论是漆面状态、机械质感还是敞篷姿态，都呈现出相当完整的完成度，兼具驾驶乐趣与日常使用的稳定感。"]', '["このアウディ R8 Spyder は低走行で整備履歴も明確に保たれており、低く構えたシルエットとミッドシップレイアウトによって、スーパーカーらしいプロポーションが際立っています。","ボディコンディション、機械的な質感、オープントップの見栄えまで総合的な完成度が高く、走る楽しさと日常での扱いやすさをバランスよく備えています。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 1, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('audi-r8-spyder', 'seed:vehicles/seed/002.png', '/api/media/vehicles/seed/002.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('audi-r8-spyder', 'seed:vehicles/seed/002.png', '/api/media/vehicles/seed/002.png', '', 0, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('audi-r8-spyder', 'seed:vehicles/seed/002.png', '/api/media/vehicles/seed/002.png', '', 0, 2);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('audi-r8-spyder', 'seed:vehicles/seed/002.png', '/api/media/vehicles/seed/002.png', '', 0, 3);
INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('ferrari-458-italia', 'ferrari', '法拉利 458 Italia', '2019', '中置跑车', 'b3.svg', '15,200', '4.5L V8', '汽油', '自动挡', '双门跑车', '后轮驱动', '竞技红', '黑红拼色真皮', '2 座', '意大利进口', 5200, 120000, 3, 'reserved', '["Ferrari 458 Italia 保留了自然吸气时代极具代表性的声浪与比例，是法拉利车系里辨识度很高的一代作品。","这台车的整体状态干净利落，既有足够鲜明的收藏气质，也保留了很纯粹的驾驶表达。"]', '["Ferrari 458 Italia は自然吸気時代を象徴するサウンドとプロポーションを色濃く残した一台で、フェラーリの中でも特に印象深い世代として知られています。","この個体は全体の状態が非常にすっきりと整っており、コレクション性を感じさせながらも、純粋なドライビングプレジャーをしっかり残しています。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 2, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('ferrari-458-italia', 'seed:vehicles/seed/003.png', '/api/media/vehicles/seed/003.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('ferrari-458-italia', 'seed:vehicles/seed/003.png', '/api/media/vehicles/seed/003.png', '', 0, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('ferrari-458-italia', 'seed:vehicles/seed/003.png', '/api/media/vehicles/seed/003.png', '', 0, 2);
