INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('bmw-x6-m', 'bmw', '宝马 X6 M', '2024', '轿跑SUV', 'b4.svg', '120', '4.4L V8', '汽油', '自动挡', '高性能 SUV', '四轮驱动', '矿石白', '黑色真皮', '5 座', '德国进口', 3600, 80000, 2, 'available', '["BMW X6 M 将轿跑 SUV 的线条与高性能动力结合得很直接，整车视觉重心低，气场也足够鲜明。","低里程与整齐的车况让它更像一台完成度很高的性能日用车，在通勤与长途场景里都保持着稳定质感。"]', '["BMW X6 M はクーペ SUV ならではの流麗なラインと高出力ユニットを素直に結びつけた一台で、低重心に見えるスタンスが強い存在感を生み出しています。","低走行かつコンディションも整っており、日常使いのしやすさを備えながら、パフォーマンスモデルとしての濃さもしっかり感じられる内容です。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 3, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('bmw-x6-m', 'seed:vehicles/seed/004.png', '/api/media/vehicles/seed/004.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('bmw-x6-m', 'seed:vehicles/seed/004.png', '/api/media/vehicles/seed/004.png', '', 0, 1);
