INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('ferrari-488-gtb', 'ferrari', '法拉利 488 GTB', '2021', '中置跑车', 'b5.svg', '8,700', '3.9L V8', '汽油', '自动挡', '双门跑车', '后轮驱动', '亮银灰', '深棕真皮', '2 座', '意大利进口', 5600, 130000, 3, 'rented', '["Ferrari 488 GTB 有着很成熟的空气动力学比例，车身线条紧凑而克制，是法拉利近代设计语言里很完整的一台作品。","这台车的状态收得很整齐，既保留了性能车应有的锋利感，也维持了足够清爽的日常可驾性。"]', '["Ferrari 488 GTB は空力処理を感じさせる完成度の高いプロポーションを持ち、引き締まったボディラインが現代フェラーリらしい美しさを際立たせています。","この個体は全体のまとまりが良く、スーパーカーらしい鋭さを保ちながらも、日常域で扱いやすいクリアな印象をしっかり残しています。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 4, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('ferrari-488-gtb', 'seed:vehicles/seed/005.png', '/api/media/vehicles/seed/005.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('ferrari-488-gtb', 'seed:vehicles/seed/005.png', '/api/media/vehicles/seed/005.png', '', 0, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('ferrari-488-gtb', 'seed:vehicles/seed/005.png', '/api/media/vehicles/seed/005.png', '', 0, 2);
