INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('lamborghini-aventador', 'lamborghini', '兰博基尼 Aventador', '2022', 'V12超跑', 'b6.svg', '12,500', '6.5L V12', '汽油', '自动挡', '双门跑车', '四轮驱动', '珍珠白', '黑色 Alcantara', '2 座', '意大利进口', 7600, 180000, 3, 'available', '["Aventador 保留了兰博基尼最具代表性的楔形姿态与 V12 气场，整车的存在感几乎不需要额外修饰。","从比例、声浪到细节完成度，它都更接近一台具有象征意味的旗舰超跑，而不只是单纯的性能机器。"]', '["Aventador はランボルギーニを象徴するウェッジシェイプと V12 の圧倒的な存在感をそのまま体現しており、余計な演出がなくても十分な迫力を放つ一台です。","プロポーション、サウンド、細部の仕上がりに至るまで、単なる高性能車というよりブランドの象徴性を背負ったフラッグシップとしての空気感があります。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 5, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-aventador', 'seed:vehicles/seed/006.png', '/api/media/vehicles/seed/006.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-aventador', 'seed:vehicles/seed/006.png', '/api/media/vehicles/seed/006.png', '', 0, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-aventador', 'seed:vehicles/seed/006.png', '/api/media/vehicles/seed/006.png', '', 0, 2);
