INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('lamborghini-huracan-evo', 'lamborghini', '兰博基尼 Huracan EVO', '2023', '中置跑车', 'b1.svg', '800', '5.2L V10', '汽油', '自动挡', '双门跑车', '四轮驱动', '珍珠黄', '黑黄拼色', '2 座', '意大利进口', 6800, 150000, 3, 'available', '["Huracan EVO 以极低里程保留了很新鲜的状态，车身比例紧凑直接，带着典型的兰博基尼视觉张力。","它的动态表达比外形更轻快，既适合城市环境中的展示感，也保留了周末驾驶时应有的灵活回应。"]', '["Huracan EVO は極低走行らしい新鮮さを保っており、引き締まったボディバランスにはランボルギーニらしい視覚的な緊張感が宿っています。","見た目の強さに対して走りの反応は軽快で、街中での見栄えと週末のドライビングの楽しさをどちらも自然に楽しめる仕上がりです。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 6, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-huracan-evo', 'seed:vehicles/seed/003.png', '/api/media/vehicles/seed/003.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-huracan-evo', 'seed:vehicles/seed/003.png', '/api/media/vehicles/seed/003.png', '', 0, 1);
