INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('lamborghini-urus-s', 'lamborghini', '兰博基尼 Urus S', '2024', '高性能SUV', 'b1.svg', '120', '4.0L V8', '汽油', '自动挡', '高性能 SUV', '四轮驱动', '石墨灰', '黑橙拼色', '5 座', '意大利进口', 6000, 130000, 2, 'available', '["Urus S 在保留实用性的同时，依然维持了很强的品牌辨识度与性能氛围，是一台边界感很少的高性能 SUV。","整车状态新、配置完整，外观与座舱都呈现出相当统一的完成度，适合被放进更高频的日常使用场景里。"]', '["Urus S は高い実用性を持ちながらも、ブランドらしいアイコン性とパフォーマンス感をしっかり残した、懐の深いハイパフォーマンス SUV です。","車両状態は非常に新しく、装備も整っており、エクステリアとインテリアの完成度に統一感があるため、日常の使用頻度が高い環境にも自然に馴染みます。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 7, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-urus-s', 'seed:vehicles/seed/004.png', '/api/media/vehicles/seed/004.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-urus-s', 'seed:vehicles/seed/004.png', '/api/media/vehicles/seed/004.png', '', 0, 1);
