INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('lamborghini-huracan-sto', 'lamborghini', '兰博基尼 Huracan STO', '2022', '中置跑车', 'b1.svg', '5,400', '5.2L V10', '汽油', '自动挡', '双门跑车', '后轮驱动', '赛道灰', '黑色 Alcantara', '2 座', '意大利进口', 7200, 160000, 3, 'reserved', '["Huracan STO 的设定明显更偏赛道取向，空气动力学细节与车身姿态都带着非常直接的功能性表达。","它保留了更纯粹的操控导向，同时也让整车在静止状态下就有很强的收藏与展示意味。"]', '["Huracan STO は明確にサーキット志向へ振られたモデルで、空力パーツや車体の構えそのものに機能性がストレートに表れています。","操作感はよりピュアで、停まっている状態でもコレクション性と展示映えの強さを感じさせる、非常に個性の立った一台です。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 8, 1);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-huracan-sto', 'seed:vehicles/seed/005.png', '/api/media/vehicles/seed/005.png', '', 1, 0);
INSERT INTO rental_images (rental_id, r2_key, url, alt, is_primary, position) VALUES ('lamborghini-huracan-sto', 'seed:vehicles/seed/005.png', '/api/media/vehicles/seed/005.png', '', 0, 1);
