INSERT INTO rentals (id, brand_key, name, year, type, icon, mileage, engine, fuel, trans, body_style, drive, body_color, interior_color, seats, origin, daily_rate, deposit, min_days, rental_status, overview_zh, overview_ja, overview_en, benefits, features, display_order, is_published) VALUES ('lamborghini-gallardo', 'lamborghini', '兰博基尼 Gallardo', '2019', '中置跑车', 'b1.svg', '28,000', '5.0L V10', '汽油', '自动挡', '双门跑车', '四轮驱动', '黑曜石', '黑色真皮', '2 座', '意大利进口', 4300, 90000, 2, 'available', '["Gallardo 保留了兰博基尼早期非常鲜明的车身比例，线条更简洁，也更容易让人联想到品牌过去的设计阶段。","这台车的状态干净稳定，既有经典时期的气质，也带着很明确的品牌历史感。"]', '["Gallardo はランボルギーニ初期の鮮烈なプロポーションを色濃く残し、よりシンプルなラインによってブランドの過去のデザイン文脈を想起させる一台です。","この個体はコンディションが安定しており、クラシックな時代感とブランドの歴史性を素直に味わえる内容にまとまっています。"]', NULL, '["一年质保服务","支持旧车置换","可选金融分期","专属交付顾问"]', '["质检认证","现车在库","全国配送","手续透明","专人跟进","售后支持","急速交付"]', 9, 1);
